### Triangle decades table


::: {.cell}

```{.r .cell-code}
tri_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png'
       style='height: 45px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>Triangle hoops over the past five decades</span>
       <span style='font-size: 12.5px; font-weight: normal; display: block; text-align: center;'>Performance across the ACC, NCAA Tournament, and overall win percentage.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png' 
       style='height: 45px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)


decade_tbl <- all_hist |> 
  dplyr::mutate(
    dplyr::across(
      where(is.numeric),
      ~ tidyr::replace_na(.x, 0)
    )
  ) |> 
  dplyr::arrange(Decade, -Titles, -Win_Percentage) |> 
  dplyr::mutate(record = paste0(Total_Wins, "-", Total_Losses)) |> 
  dplyr::relocate(Win_Percentage, .after = Titles) |>
  dplyr::mutate(
    Titles = dplyr::case_when(
      Titles %% 1 == 0 ~ strrep("trophy,", Titles),
      Titles %% 1 != 0 ~ paste0(strrep("trophy,", floor(Titles)), "trophy"))
  ) |> 
  cbbplotR::gt_cbb_teams(team, team, include_name = FALSE) |> 
  cbbplotR::gt_cbb_teams(team_two, team_two, include_name = FALSE) |> 
  dplyr::group_by(Decade) |> 
  gt::gt() |> 
  gt::fmt_markdown(team) |> 
  gt::fmt_markdown(team_two) |> 
  gtUtils::gt_theme_gtutils() |> 
  gt::fmt_icon(
    columns = c(Titles),
    rows = c(1, 2, 4, 5, 7, 8, 10, 11),
    fill_color = "orange"
  ) |> 
  gt::cols_hide(columns = c(Total_Wins, Total_Losses)) |> 
  gt::fmt_number(Win_Percentage, decimals = 3) |> 
  gtExtras::gt_merge_stack(
    col1 = Win_Percentage,
    col2 = record,
    palette = c("black", "#333333")
  ) |> 
  gtUtils::gt_column_subheaders(
    Win_Percentage = list(heading = "Win %", subtitle = "W-L"),
    ACCT = list(heading = "Titles", subtitle = "Tournament"),
    RS = list(heading = "Regular", subtitle = "Season"),
    F4 = list(heading = "Final Fours", subtitle = "# of times"),
    Titles = list(heading = "Titles", subtitle = "# of titles"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |> 
  gt::cols_label(team = "", team_two = "") |> 
  gt::tab_spanner(
    columns = c(ACCT, RS),
    label = "ACC Championships"
  ) |> 
  gt::tab_spanner(
    columns = c(F4, Titles),
    label = "NCAA Tournament"
  ) |> 
  gt::cols_label(
    Decade = ""
  ) |> 
  gt::cols_nanoplot(
    columns = Yearly_Win_Pcts,
    reference_line = .70,
    autohide = TRUE,
    plot_type = "line",
    new_col_label = "Over time",
    before = "team_two",
    options = gt::nanoplot_options(
      data_area_fill_color = "#C5C5FF",
      reference_line_color = "#333333",
      show_data_area = TRUE,
      show_data_points = FALSE
    )
  ) |> 
  gt::tab_header(title = gt::html(tri_header)) |>
  gt::tab_source_note(source_note = gt::html("<hr>Over time column shows win percentage by season throughout the decade (dashed line indicates a .700 win percentage)<br>Data grouped by each decade, and sorted by National titles first, and win percentage second <br>Decades include the season's final year (i.e. 2009-10 is part of the 2010s)<hr><br><b>Table by Chris at Bless your Chart | data via sports-reference.com | April 9, 2025</b>")) |> 
  gt::data_color(
    columns = c(ACCT, RS, F4, Win_Percentage),
    direction = c("column"),
    method = c("numeric"),
    palette = c("#d7191c", "#fdae61", 
                "#ffffbf", "#a6d96a", 
                "#1a9641"),
    alpha = 0.6
  ) |>
  gt::cols_align(team, align = "right") |> 
  gt::tab_style(
    locations = gt::cells_column_labels(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = "650",
      size = gt::px(14)
    )
  ) |> 
  gt::tab_style(
    locations = gt::cells_body(columns = Decade),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = "bold"
    )
  ) |> 
  gt::tab_style(
    locations = gt::cells_column_spanners(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = 850,
      size = gt::px(14)
    )
  ) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |>
  gt::tab_style(
    locations = gt::cells_row_groups(),
    style = list(
      gt::cell_text(
        font = gt::google_font("Signika Negative"),
        weight = 850,
        size = gt::px(16),
        color = "black",
        align = "left"
      ),
      gt::cell_fill(
        color = "#C5C5FF"
      )
    )
  ) |> 
  gt::tab_style(
    style = list(
      gt::cell_text(font = gt::google_font("Signika Negative")
      )
    ),
    locations = gt::cells_body(
      columns = c(team)
    )
  ) |> 
  gtUtils::gt_border_grid(color = "black",
                          weight = 1.5,
                          include_labels = FALSE) |> 
  gtUtils::gt_border_bars_bottom(c("#012169", "#56a0d3", "#CC0000")) |> 
  gt::tab_options(table.width = gt::px(600))


gtUtils::gt_save_crop(
  decade_tbl,
  file = "tri_decade_tbl.png",
  whitespace = 60,
  bg = "#FFFDF5"
)

decade_tbl
